// Alert triggers when Apache server uptime resets, indicating a restart.
// A restart is detected when the current uptime is significantly lower than the previous maximum,
// which suggests the server was restarted.
// You can adjust the threshold value by modifying the uptime_seconds in the WHERE clause.
FROM metrics-apachereceiver.otel-*
| STATS max_uptime = MAX(metrics.apache.uptime), min_uptime = MIN(metrics.apache.uptime) BY resource.attributes.host.name
| WHERE max_uptime IS NOT NULL AND min_uptime IS NOT NULL
| EVAL uptime_delta = max_uptime - min_uptime
| WHERE min_uptime < 300 AND uptime_delta > 300
| KEEP resource.attributes.host.name, min_uptime, max_uptime, uptime_delta
| SORT min_uptime ASC
